test('keeps mobile chat runtime stylesheet in the ui layer', () => {
  assert.match(chatScreenSource, /import \{ useChatRuntimeMobileStyleSlots \} from '\.\.\/ui\/ChatRuntimeMobileStyles';/);
  assert.match(chatScreenSource, /const \{ chatRuntimeChrome \} = useChatRuntimeMobileStyleSlots\(\);/);
  assert.doesNotMatch(chatScreenSource, /useSafeAreaInsets/);
  assert.doesNotMatch(chatScreenSource, /useTheme/);
  assert.doesNotMatch(chatScreenSource, /darkSpinner|lightSpinner/);
  assert.match(chatRuntimeMobileStylesSource, /import \{ useSafeAreaInsets \} from 'react-native-safe-area-context';/);
  assert.match(chatRuntimeMobileStylesSource, /import \{ useTheme \} from '\.\/ThemeProvider';/);
  assert.match(chatRuntimeMobileStylesSource, /const darkSpinnerSource = require\('\.\.\/\.\.\/assets\/loading-spinner\.gif'\);/);
  assert.match(chatRuntimeMobileStylesSource, /const lightSpinnerSource = require\('\.\.\/\.\.\/assets\/light-spinner\.gif'\);/);
  assert.doesNotMatch(chatScreenSource, /createChatRuntimeMobileStyles\(theme\)/);
  assert.doesNotMatch(chatScreenSource, /function createStyles/);
  assert.doesNotMatch(chatScreenSource, /StyleSheet\.create/);
  assert.doesNotMatch(chatScreenSource, /getChatRuntimeMobileChromeStyleRenderState,/);
  assert.match(chatRuntimeMobileStylesSource, /export function createChatRuntimeMobileStyles/);
  assert.match(chatRuntimeMobileStylesSource, /const insets = useSafeAreaInsets\(\);\s+const \{ theme, isDark \} = useTheme\(\);\s+const bottomInset = insets\.bottom;/);
  assert.match(chatRuntimeMobileStylesSource, /chatRuntimeSpinnerSource = useMemo\(\s+\(\) => createChatRuntimeThemeSpinnerSource\(\{\s+isDark,\s+darkSource: darkSpinnerSource,\s+lightSource: lightSpinnerSource,\s+\}\),\s+\[isDark\],\s+\);/);
  assert.match(chatRuntimeMobileStylesSource, /const styles = useMemo\(\(\) => createChatRuntimeMobileStyles\(theme\), \[theme\]\);/);
  assert.doesNotMatch(chatScreenSource, /\s+styles,\s+\} = useChatRuntimeMobileStyleSlots/);
  assert.doesNotMatch(chatRuntimeMobileStylesSource, /return \{[\s\S]*?\s+styles,\s+[\s\S]*?\};/);
  assert.match(chatRuntimeMobileStylesSource, /createChatMessageRuntimeChromeSlots,[\s\S]*?createChatMessageRuntimeChromeStyleSlots,[\s\S]*?createChatMessageRuntimeSurfaceChromeSlots,[\s\S]*?createChatRuntimeChromeSlots,[\s\S]*?createChatRuntimeHeaderChromeSlots,[\s\S]*?\} from '@dotagents\/shared\/session-presentation';/);
  assert.match(sessionPresentationSource, /export function createChatRuntimeHeaderChromeSlots/);
  assert.match(sessionPresentationSource, /export function createChatMessageRuntimeChromeStyleSlots/);
  assert.match(sessionPresentationSource, /export function createChatMessageRuntimeChromeSlots/);
  assert.match(sessionPresentationSource, /export function createChatMessageRuntimeSurfaceChromeSlots/);
  assert.match(sessionPresentationSource, /export function createChatRuntimeChromeSlots/);
  assert.match(chatRuntimeMobileStylesSource, /const chatRuntimeHeaderChrome = useMemo\(\s+\(\) => createChatRuntimeHeaderChromeSlots\(\{\s+colors: chatRuntimeChromeEnvironment\.colors,\s+spinnerSource: chatRuntimeSpinnerSource,\s+styles: chatRuntimeHeaderStyles,\s+\}\),/);
  assert.match(chatRuntimeMobileStylesSource, /const chatRuntimeChromeEnvironmentProps = useMemo\(\s+\(\) => \(\{\s+platform: chatRuntimeChromeEnvironment\.platform,\s+\}\),/);
  assert.match(chatRuntimeMobileStylesSource, /const chatRuntimeChrome = useMemo\(\s+\(\) => createChatRuntimeChromeSlots\(\{\s+environment: chatRuntimeChromeEnvironmentProps,\s+header: chatRuntimeHeaderChrome,\s+messageRuntime: chatMessageRuntimeChrome,\s+surface: chatMessageRuntimeSurfaceChrome,\s+\}\),/);
  assert.doesNotMatch(chatScreenSource, /chatRuntimeHeaderStyles/);
  assert.match(chatRuntimeMobileStylesSource, /getChatRuntimeMobileChromeStyleRenderState,/);
  assert.match(chatRuntimeMobileStylesSource, /return StyleSheet\.create\(\{/);
});

